import{_ as e,o,c as i,ag as l}from"./chunks/framework.DbM0IBjv.js";const u=JSON.parse('{"title":"OpenSpec 最佳实践与常见错误","description":"","frontmatter":{},"headers":[],"relativePath":"guide/openspec/best-practices.md","filePath":"guide/openspec/best-practices.md","lastUpdated":1775568446000}'),r={name:"guide/openspec/best-practices.md"};function s(t,a,p,c,h,n){return o(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="openspec-最佳实践与常见错误" tabindex="-1">OpenSpec 最佳实践与常见错误 <a class="header-anchor" href="#openspec-最佳实践与常见错误" aria-label="Permalink to &quot;OpenSpec 最佳实践与常见错误&quot;">​</a></h1><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><h3 id="_1-变更名要窄且清晰" tabindex="-1">1) 变更名要窄且清晰 <a class="header-anchor" href="#_1-变更名要窄且清晰" aria-label="Permalink to &quot;1) 变更名要窄且清晰&quot;">​</a></h3><ul><li>✅ <code>add-order-checkout</code></li><li>❌ <code>optimize-system</code></li></ul><p>名称越具体，评审与追踪越轻松。</p><h3 id="_2-proposal-两分钟可读完" tabindex="-1">2) Proposal 两分钟可读完 <a class="header-anchor" href="#_2-proposal-两分钟可读完" aria-label="Permalink to &quot;2) Proposal 两分钟可读完&quot;">​</a></h3><p>至少回答四件事：</p><ol><li>为什么做（Why）</li><li>做什么（What）</li><li>不做什么（Non-Goals）</li><li>风险是什么（Risks）</li></ol><h3 id="_3-specs-写-场景-不要写-感受" tabindex="-1">3) Specs 写“场景”，不要写“感受” <a class="header-anchor" href="#_3-specs-写-场景-不要写-感受" aria-label="Permalink to &quot;3) Specs 写“场景”，不要写“感受”&quot;">​</a></h3><ul><li>✅ Given/When/Then</li><li>❌ “页面更友好”“体验更好”</li></ul><p>场景可测试，才能稳定实现。</p><h3 id="_4-tasks-要小而有序" tabindex="-1">4) Tasks 要小而有序 <a class="header-anchor" href="#_4-tasks-要小而有序" aria-label="Permalink to &quot;4) Tasks 要小而有序&quot;">​</a></h3><p>每个任务最好 30~90 分钟可完成；后置任务依赖前置任务明确可见。</p><h3 id="_5-apply-前先审规范" tabindex="-1">5) apply 前先审规范 <a class="header-anchor" href="#_5-apply-前先审规范" aria-label="Permalink to &quot;5) apply 前先审规范&quot;">​</a></h3><p><code>/opsx:ff</code> 生成很快，但一定先人工审 proposal/specs/design/tasks，再 <code>/opsx:apply</code>。</p><h3 id="_6-计划与编码分会话" tabindex="-1">6) 计划与编码分会话 <a class="header-anchor" href="#_6-计划与编码分会话" aria-label="Permalink to &quot;6) 计划与编码分会话&quot;">​</a></h3><p>长会话会污染上下文。规划稳定后开新会话执行，输出质量更高。</p><h3 id="_7-完成即归档" tabindex="-1">7) 完成即归档 <a class="header-anchor" href="#_7-完成即归档" aria-label="Permalink to &quot;7) 完成即归档&quot;">​</a></h3><p><code>/opsx:archive</code> 保持 <code>changes/</code> 目录“只放进行中变更”。</p><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><h3 id="错误-1-一条变更塞太多功能" tabindex="-1">错误 1：一条变更塞太多功能 <a class="header-anchor" href="#错误-1-一条变更塞太多功能" aria-label="Permalink to &quot;错误 1：一条变更塞太多功能&quot;">​</a></h3><p>症状：任务爆炸、评审困难、返工频繁。</p><p>修复：拆成多个 change，按业务流拆分。</p><h3 id="错误-2-设计写成实现细节" tabindex="-1">错误 2：设计写成实现细节 <a class="header-anchor" href="#错误-2-设计写成实现细节" aria-label="Permalink to &quot;错误 2：设计写成实现细节&quot;">​</a></h3><p>症状：design.md 充满代码片段，但缺少取舍理由。</p><p>修复：design 写“为什么这样做”，代码细节放实现阶段。</p><h3 id="错误-3-spec-与代码不同步" tabindex="-1">错误 3：Spec 与代码不同步 <a class="header-anchor" href="#错误-3-spec-与代码不同步" aria-label="Permalink to &quot;错误 3：Spec 与代码不同步&quot;">​</a></h3><p>症状：代码做了但文档没更新，后续 AI 继续按旧规范执行。</p><p>修复：每次变更后执行 verify + 同步 specs。</p><h3 id="错误-4-任务没有验收标准" tabindex="-1">错误 4：任务没有验收标准 <a class="header-anchor" href="#错误-4-任务没有验收标准" aria-label="Permalink to &quot;错误 4：任务没有验收标准&quot;">​</a></h3><p>症状：任务“看起来完成”但无法验证。</p><p>修复：每个任务加可验证输出（文件/API/测试结果）。</p><h2 id="实操检查清单" tabindex="-1">实操检查清单 <a class="header-anchor" href="#实操检查清单" aria-label="Permalink to &quot;实操检查清单&quot;">​</a></h2><ul><li>[ ] proposal 有 Why / What / Non-Goals / Risks</li><li>[ ] specs 每个 requirement 至少一个 scenario</li><li>[ ] tasks 顺序与依赖清晰</li><li>[ ] apply 前人工审查完成</li><li>[ ] verify 通过后再 archive</li></ul>',34)])])}const _=e(r,[["render",s]]);export{u as __pageData,_ as default};
